// Three runbooks as items for ingestion. content + metadata per doc.
const runbooks = [
  {
    title: "Database Connection Pool Exhaustion",
    service: "checkout-api",
    content: `Runbook: Database Connection Pool Exhaustion. Symptoms: services report "Connection pool exhausted" or "max connections reached"; downstream calls like the payment gateway time out under load; latency spikes correlate with traffic peaks. Likely root causes: pool max size too low (common default 20); leaked connections not returned to the pool; long-running queries holding connections; a slow downstream dependency causing connections to pile up. Investigation: check pool max and active count; correlate error timestamps with traffic and downstream latency; look for long-duration queries; check recent deploys that changed pool config. Remediation: increase pool max e.g. 20 to 50; add a circuit breaker on slow downstream dependencies; fix connection leaks with a finally block; add pool saturation alerting.`
  },
  {
    title: "OutOfMemoryError Java Heap Space",
    service: "inventory",
    content: `Runbook: OutOfMemoryError Java heap space. Symptoms: service logs OutOfMemoryError and may crash or restart; memory climbs then the process is OOMKilled; often follows a deploy or data volume change. Likely root causes: heap size -Xmx too small; memory leak from caches without eviction or static collections; loading large datasets fully into memory. Investigation: capture a heap dump and inspect largest retainers; check recent deploys changing caching or batch sizes; review GC logs. Remediation: increase -Xmx short term; add cache eviction and size bounds; stream large datasets.`
  },
  {
    title: "Auth Token Refresh Failures",
    service: "auth-service",
    content: `Runbook: Auth token refresh failures. Symptoms: spikes in 401/403 across services depending on auth-service; logs show token refresh failures or expired tokens. Likely root causes: clock skew causing premature expiry; auth-service downtime or rate limiting during refresh storms; misconfigured token TTL after a deploy. Investigation: check auth-service health and error rate; verify clock sync; confirm token TTL config. Remediation: stagger refreshes with jitter; fix clock sync; cache valid tokens until shortly before expiry.`
  }
];

return runbooks.map(r => ({
  json: {
    content: r.content,
    metadata: { title: r.title, service: r.service, source: "runbook" }
  }
}));
